- `ntm --robot-bulk-assign` assigns tasks to idle Codex and Claude agents
- Clear logging when assignments fail (with reason)","status":"closed","priority":1,"issue_type":"task","assignee":"TopazBadger","created_at":"2026-01-25T02:24:09.091119838Z","created_by":"ubuntu","updated_at":"2026-01-25T05:53:21.859325482Z","closed_at":"2026-01-25T05:53:21.858886615Z","close_reason":"Bulk-assign now treats bv triage status=open as ready; added unit test (bulk_assign). Tests blocked by existing import-cycle in internal/robot.","source_repo":".","compaction_level":0,"original_size":0,"labels":["cli"],"dependencies":[{"issue_id":"beads_rust-19my.3","depends_on_id":"beads_rust-19my","type":"parent-child","created_at":"2026-03-08T22:47:30Z","created_by":"import","metadata":"{}","thread_id":""},{"issue_id":"beads_rust-19my.3","depends_on_id":"beads_rust-19my.2","type":"blocks","created_at":"2026-03-08T22:47:30Z","created_by":"import","metadata":"{}","thread_id":""}]}
